var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음… 어디보자… 이걸 누르면 되는 거였나?","JPN":"うん……えっと……ここを押すんだったっけ？","ENG":"Hmm... Let's see... Is this the right button?","TWN":"嗯…我看看…按下這個就好嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭔가 돌아가고 있는 거 같은데 녹화 잘 되고 있는거 맞겠지? ","JPN":"動いているみたいだけど、録画できてるのかな？ ","ENG":"I think something's running. The recording should be fine, right?","TWN":"好像有在動的樣子，應該有在錄吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어흠, 어… 그러니까 오늘 사장의 생일이라고 들었거든.","JPN":"コホン、あ……えっと、今日は社長の誕生日だって聞いて。","ENG":"Ahem, uh... Well, I heard it was your birthday today, Boss.","TWN":"咳咳…聽說今天是老闆的生日。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"생일축하라… 그런 말을 들어본 게 언제였는지 기억도 가물가물한데.","JPN":"お誕生祝い……なんて言葉聞いたのいつぶりか、よく思い出せないな。","ENG":"I can't really remember the last time I heard someone say happy birthday...","TWN":"生日快樂…我都不記得上次有人對我說這句話是什麼時候了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"생일… 축하해 사장님. 아하하. 조금 어색하네…….","JPN":"誕生日……おめでと、社長。あはは。ちょっと照れるね……","ENG":"Happy... birthday, Boss. Ah ha ha. This is a little awkward...","TWN":"老闆…生日快樂，哈哈哈，真是尷尬……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이곳에 입사하고 사장의 도움이 있었기에 지금까지 잘 헤쳐나올 수 있었던 것 같아.","JPN":"ここに入社して、社長の助けがあったから、今までうまくやってこれたんだと思う。","ENG":"It was thanks to you that I managed to make it this far.","TWN":"來到這裡之後，因為有老闆的幫忙，我才能關關難過關關過。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일단은 고맙다고 말해주고 싶어. 진심으로.","JPN":"とりあえず、ありがとうって言いたかったんだ。心から。","ENG":"So I want to start off by saying thank you. Truly.","TWN":"首先，我想真心地跟老闆說一聲，謝謝。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"생일 기념으로 사장실 앞에다 선물도 놔뒀으니 확인해 봐. 내용물은 말하지 않을게.","JPN":"誕生日の記念に社長室の前にプレゼントを置いておいたから、見てみて。どんなものかは言わないでおくよ。","ENG":"I left a birthday gift in front of the CEO's office, so check it out. I won't spoil what's inside.","TWN":"今天是你的生日，禮物就放在老闆辦公室前，你自己去看看吧。至於送什麼禮物我是不會說的。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"포장을 뜯어보는 설렘도 중요…….","JPN":"包みを開く時のどきどきも大事……","ENG":"The excitement of unwrapping the gift is also immeasurable–","TWN":"拆禮物時的期待感也是很重要的……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나양? 뭐하고 계신 건가요?","JPN":"ミナさん？　何をしているんですか？","ENG":"Mina? What are you doing?","TWN":"米娜？你在幹嘛？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으앗?! 서, 선배?!","JPN":"うわっ！？　せ、先輩！？","ENG":"W-whoa! Sh-Shiyoon?!","TWN":"蛤？！前…前輩？！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"멀리서 혼잣말로 대화하고 계신 거 같아서 다가가 봤는데 뭘 찍고 계신 건가요?","JPN":"遠くで何やら一人で話しているように見えて近くに来てみたんですが、何を撮っていたんですか？","ENG":"It seemed like you were talking to yourself from afar. What are you filming?","TWN":"我看你好像一個人在自言自語，就過來看一下。你是在拍什麼東西？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그러니까… 딱히 수상한 건 아니야!","JPN":"こ、これは……怪しいものじゃないよ！","ENG":"I-it's... nothing suspicious!","TWN":"那個……我不是在做壞事！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하하. 수상한 행동을 하는 사람들의 단골 멘트네요.","JPN":"ハハハ。怪しい行動をしている人のおきまりのセリフですね。","ENG":"Hah hah hah. That's exactly what a suspicious person would say.","TWN":"哈哈哈，做壞事的人通常都會這麼說。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아하. 곧 사장님 생일이니까 기념 영상을 찍어보자고 사내 공지글을 봤었는데 예상대로네요.","JPN":"なるほど。もうすぐ社長の誕生日なので記念動画を撮ろうって社内連絡にありましたが、思っていた通りですね。","ENG":"Aha. I remember seeing the company notice suggesting that we film a congratulations video for Boss's birthday.","TWN":"哈，我有看到公司布告欄上貼的公告說，老闆的生日快到了，要請大家拍祝賀影片，你就是在拍這個吧？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양이 그렇게나 사장님을 생각해 주실 줄은 몰랐네요. 이거 다시 보게 되는걸요?","JPN":"ミナさんがそこまで社長の事を考えておられるとは知りませんでした。見直しましたよ。","ENG":"I didn't know you cared about Boss that much. I'm quite surprised.","TWN":"沒想到你對老闆的事如此上心，令人寡目相看呢。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알고 있었잖아! 한참을 기다려도 아무도 안 오길래 먼저 찍고 있던건데……!","JPN":"知ってたんじゃない！　ずっと待ってたのに誰も来ないから、先に撮っていたのに……！","ENG":"You knew about it?! I just started filming because no one came, even though I waited for a long time...!","TWN":"那你還明知故問！我等了半天都沒有人來，想說乾脆我自己先拍……！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"여기에다 대고 말하면 되는 거죠? 생일 축하드립니다 사장님. 그럼 앞으로도 잘 부탁드릴게요.","JPN":"ここに向かって話したらいいんですよね？　お誕生日おめでとうございます、社長。これからもよろしくおねがいします。","ENG":"Do I speak into this mic? Happy birthday, Boss. Hope you have a great day.","TWN":"對著這邊說話就可以了吧？老闆生日快樂，之後也請多多指教。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"엄청 짧게 끝내네. 고작 한마디만 하는거야?","JPN":"すごく短いね。たった一言だけなの？","ENG":"That's pretty short. Is that all you have to say?","TWN":"還真短，你就只有這二句話要說嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하고 싶은 말은 짧고 간결하게. 라고들 하잖아요? 하하하.","JPN":"言いたいことは短く簡潔にって言うじゃないですか。ハハハ。","ENG":"You know what they say, say more with less. Hah hah hah.","TWN":"說話不是簡潔有力才好嗎？哈哈哈。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래도 나름 선물도 준비해 놓았죠. 좋아하실지는 잘 모르겠지만요.","JPN":"でも、プレゼントも一応用意しました。喜んでくれるかはわかりませんが。","ENG":"I still got him a present. Although I'm not sure if he'll like it.","TWN":"不過我有準備個禮物啦，只是不知道老闆會喜歡嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양은 어떤 선물을 준비하셨나요?","JPN":"ミナさんはどんなプレゼントにしたんですか？","ENG":"What kind of present did you get him, Mina?","TWN":"米娜你送什麼禮物？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나? 난 별건 아니고 그냥 평범한…….","JPN":"私？　なんてことない、普通の……","ENG":"Me? Nothing special, just an ordinary–","TWN":"我？沒什麼特別的，就普通的……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"사장실 앞에 정성스레 포장된 상자는 누가 놓은 걸까?","JPN":"社長室の前の丁寧に包装されてる箱って誰が置いたの？","ENG":"I wonder who put the neatly wrapped box in front of the CEO's office?","TWN":"老闆辦公室前有個包裝很精美的箱子，不知道是誰放的呢？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"차가운 독고다이 타입인줄 알았는데 나름 따뜻한 면도 있었네?","JPN":"冷めてる一匹狼タイプだと思ってたのに、温かい一面もあったのね？","ENG":"I thought you were a lone wolf. Didn't know you had a touchy-feely side.","TWN":"我還以為你是孤獨一匹狼，沒想到也有溫暖的一面。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"엇, 뭐야?! 언제부터 옆에 있었던 거야!","JPN":"わっ、なに！？　いつの間に横に来てたの？","ENG":"W-what?! How long were you standing there for?!","TWN":"啊，你幹嘛啦？！你什麼時候來的！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"오호? 유미나 양이 정성스런 포장이라구요? 어떤 물건이던가요?","JPN":"へえ？　ミナさんが丁寧に包装を？　どんなものなんでしょうか？","ENG":"Oh? Yoo Mina, putting effort into wrapping? What kind of item was it?","TWN":"喔？劉米娜精美的包裝嗎？裡面是什麼呢？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"남의 선물을 뜯어보는 건 예의가 아니잖아요.","JPN":"他人のプレゼントを開けるのはご法度でしょう。","ENG":"It's not polite to open other people's gifts.","TWN":"拆別人的禮物是不禮貌的。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그래도 미나가 사장님을 위해 준비한 선물이 어떤 건지는 너무 궁금한데?","JPN":"でも、ミナが社長のために用意したプレゼントが何なのかはすごく気になるけどね？","ENG":"Still, I am really curious about what kind of gift Mina got for Boss?","TWN":"不過真的很好奇米娜到底送老闆什麼欸？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그건 말하면 안 되지! 김 다 샐 거 아냐…….","JPN":"そ、それは言えないよ！　つまんないじゃん……","ENG":"I-I can't tell you that! It'll ruin the surprise...","TWN":"怎…怎麼可以說！這樣會漏餡兒……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"흐음? 그럼 어쩔 수 없지 뭐.","JPN":"ふうん？　それじゃ、仕方ないわね。","ENG":"Hmm? Oh well. Fine.","TWN":"是嗎？那好吧。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"미나가 놓고 간 선물은 사장님과 유미나 단둘만의 아주 위험한 프라이버시적인 물건이라는걸로……!","JPN":"ミナが置いていったプレゼントは、社長とミナ、二人だけのと～っても危ない私的なものってことで……！","ENG":"I'll just assume that Mina left a present that was very private and intimate to Boss and Mina...!","TWN":"那就當作，米娜送的是只有他們二人可以知道的私密禮物……！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"컵라면이야 컵라면! 딱 일주일 동안만 한정 판매하는 엄청 구하기 힘든 거였다고!","JPN":"カップ麺だよ、カップ麺！　たった1週間しか販売しない限定品で、手に入れるのが大変だったんだから！","ENG":"It's cup noodles! Cup noodles! I had a hard time getting it, because it was a limited edition that was only sold for a week!","TWN":"是杯麵啦！是只賣一週的超難買限量泡麵！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아하하… 생일 선물로 컵라면이라니. 미나 양 답긴 하네요.","JPN":"アハハ……誕生日プレゼントがカップ麺とは。ミナさんらしいですね。","ENG":"Ah hah hah... Cup noodles as a birthday gift? That does sound like Mina.","TWN":"哈哈哈…生日禮物竟然送泡麵，很有米娜的風格呢。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"휴가까지 써서 주변 편의점을 다 돌아다니고 힘들게 다섯 개 구한 걸 무려 세 개나 챙겨준건데…….","JPN":"休暇まで使ってこの辺のコンビニを全部回って、やっと5個買えたやつを3個も入れたのに……","ENG":"I gave him three out of the five I got after using my vacation time to go around all the nearby convenience stores to search for it...","TWN":"我用休假時間跑遍附近所有的商店，好不容易才買到五個。我送老闆三個欸……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"알았어 알았어. 결국엔 컵라면이라는 거지? 사장님께서 정말 기뻐하실 거야 미나야.","JPN":"わかった、わかった。つまりはカップ麺ってことでしょ？　社長にとても喜ばれるわよ、ミナ。","ENG":"Okay, okay. So it's cup noodles. The Boss will be really happy, Mina.","TWN":"好啦好啦，總之就是泡麵嘛？老闆一定會很開心的，米娜。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"생일 축하드립니다 사장님. 생일날이 아니더라도 감사드리고 싶은 게 정말 많았어요.","JPN":"お誕生日おめでとうございます、社長。お誕生日でなくても、感謝をお伝えしたいことがたくさんありました。","ENG":"Happy birthday, Boss. I wanted to express my gratitude even before it was your birthday.","TWN":"老闆生日快樂，就算不是老闆生日，我也有很多想感謝老闆的事。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"선물이라기엔 뭐 하지만 저희도 사장님을 위해 준비했거든요.","JPN":"大したものではありませんが、私たちも社長のためにプレゼントを用意しました。","ENG":"It's not much, but we got something for you too.","TWN":"也不算是什麼禮物啦，總之就是我們替老闆準備的。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저희 소대원들과 돈을 모아 샀으니 분명 마음에 드실 거예요. 기대하고 열어주세요~","JPN":"私たちの小隊でお金を集めて購入したので、きっと気に入っていただけると思います。期待していてくださいね～","ENG":"My squad members chipped in for this gift, so I'm sure you'll like it. Have fun unwrapping it!","TWN":"這是我們小隊一起集資買的，老闆你一定會喜歡的。用期待的心打開它吧～"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이제 됐겠지? 더 이상 와주는 사람은 없는 것 같으니까 여기까지 녹화해야 하지 않을까?","JPN":"これでいいでしょ？　もう来る人もいないでしょうから、録画はこのくらいでいいんじゃない？","ENG":"That should be good, right? Let's end the video here, since there doesn't seem to be anyone else coming.","TWN":"這樣可以了吧？應該沒其他人要錄了吧？我要結束錄影囉？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐만, 그, 그러니까… 다시 한번 생일 축하해.","JPN":"ちょっと待って、だ、だから……もう一度、お誕生日おめでとう。","ENG":"Wait, u-um... Happy birthday, again.","TWN":"等一下，我…想再說一次，祝老闆生日快樂。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"모처럼 준비한 선물들도 있으니까 풀어보지 않으면 실례잖아?","JPN":"せっかく用意したプレゼントもあるんだし、開けてみなきゃ失礼だよね？","ENG":"It would be rude to leave your presents unopened.","TWN":"這些是大家特地準備的禮物，壽星不親手拆的話很沒禮貌吧？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"생일 당일날 와서 직원들 앞에서 선물 포장 열어보는 것도 좋을 것 같아.","JPN":"誕生日の日に来て、社員の前でプレゼントの包みを開けてみせるのもいいかもね。","ENG":"I think it would be nice if you were to come here on your birthday and unwrap the gifts with the employees.","TWN":"希望老闆可以在生日當天在員工面前拆禮物。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"바쁘다는 말은 다 핑계인 거 알지? 꼭 와야해?","JPN":"忙しいってのは言い訳だってこと、わかってるよね？　絶対に来てよ？","ENG":"Saying you're busy is just an excuse. You have to make it, okay?","TWN":"我們不接受忙碌這個理由，一定要來喔！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그래서 미나야. 정말로 컵라면이었어?","JPN":"ところで、ミナ。本当にカップ麺だったの？","ENG":"So, Mina. Was it really cup noodles?","TWN":"我說米娜，你真的送泡麵喔？"},"stage":{"bg":"BLACK","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아까 상자를 흔들어 보니까 컵라면치고는 조금 무게가 있는 것 같던데?","JPN":"さっき箱を振ってみたんだけど、カップ麺の割にはちょっと重かったわよ？","ENG":"I shook the box earlier, and it seemed like it was heavier than just cup noodles.","TWN":"我剛搖了一下箱子，蠻沉的欸，但泡麵應該很輕吧？"},"stage":{"bg":"BLACK","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무, 무슨 소릴 하는 거야! 그냥 컵라면이 아니라 스페셜 에디션이라구.","JPN":"な、なに言ってるの！　ただのカップ麺じゃなくて、スペシャルエディションなんだって。","ENG":"W-what are you talking about?! They aren't JUST cup noodles, they're special edition cup noodles.","TWN":"有…有什麼好奇怪的！就說不是普通的泡麵，是特別限定版！"},"stage":{"bg":"BLACK","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하하. 요즘 컵라면은 엄청 호화롭네요.","JPN":"ハハハ。最近のカップ麺はとっても豪華なんですね。","ENG":"Hah hah hah. Cup noodles these days are pretty fancy.","TWN":"哈哈哈，最近的泡麵花樣還真多呢。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래도 마지막에 사장님을 위해 굳이 몇 마디 더 해주신 걸 보면…….","JPN":"それにしても、最後に社長のためにあえて一言二言付け加えるところを見ると……","ENG":"Still, based on the way you had an extra speech for Boss at the end...","TWN":"不過你最後還要再硬補幾句話……"},"stage":{"bg":"BLACK","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양이 사장님을 정말 각별히 생각하시는 것 같은데요? 하하.","JPN":"ミナさんの中で社長はそれだけ特別な存在ってことですかね？　ハハ。","ENG":"Seems like he's really special to you, Mina. Hah hah.","TWN":"米娜，你應該真的很看重老闆吧？哈哈～"},"stage":{"bg":"BLACK","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"둘 다 좀 그만하라고!","JPN":"もう、二人ともいい加減にしてよ！","ENG":"Stop it, both of you!","TWN":"你們真的很吵欸！"},"stage":{"bg":"BLACK","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};